import * as fs from 'fs';
import * as os from 'os';
import * as path from 'path';
import {
  appendSignalEnvelope,
  buildRunnerRegisterPayload,
  buildRunnerUsedSignalKey,
  dedupeSignalEnvelope,
  normalizeRunnerContext,
  sanitizeRunnerMetadata,
} from '../src/runner-context';
import { createSignalEnvelope } from '../src/signal-envelope';

describe('runner context utilities', () => {
  const envBackup: Record<string, string | undefined> = {};

  beforeEach(() => {
    for (const k of [
      'GITHUB_REPOSITORY',
      'GITHUB_SHA',
      'GITHUB_RUN_ID',
      'GITHUB_RUN_ATTEMPT',
      'GITHUB_JOB',
      'RUNNER_NAME',
    ]) {
      envBackup[k] = process.env[k];
    }
    process.env.GITHUB_REPOSITORY = 'acme/app';
    process.env.GITHUB_SHA = 'abc123def4567890123456789012345678901234';
    process.env.GITHUB_RUN_ID = '42';
    process.env.GITHUB_RUN_ATTEMPT = '1';
    process.env.GITHUB_JOB = 'build';
    process.env.RUNNER_NAME = 'GitHub Actions 1';
  });

  afterEach(() => {
    for (const [k, v] of Object.entries(envBackup)) {
      if (v === undefined) delete process.env[k];
      else process.env[k] = v;
    }
  });

  it('buildRunnerUsedSignalKey prefers workflowJobId', () => {
    const { idempotency } = normalizeRunnerContext({ workflowJobId: '999' });
    expect(buildRunnerUsedSignalKey(idempotency)).toBe(
      'github-actions:acme/app:42:1:job-999:runner.used',
    );
  });

  it('buildRunnerUsedSignalKey falls back to jobName', () => {
    const { idempotency } = normalizeRunnerContext();
    expect(buildRunnerUsedSignalKey(idempotency)).toBe(
      'github-actions:acme/app:42:1:build:runner.used',
    );
    expect(buildRunnerUsedSignalKey(idempotency)).not.toContain('GitHub Actions');
  });

  it('buildRunnerRegisterPayload matches backend RegisterRunnerDto fields', () => {
    const { ghCtx } = normalizeRunnerContext({ workflowJobId: '555' });
    const body = buildRunnerRegisterPayload({
      ghCtx,
      buildId: 'bld_1',
      correlationId: 'corr-1',
    });
    expect(body).toMatchObject({
      repository: 'acme/app',
      workflowRunId: '42',
      workflowJobId: '555',
      jobName: 'build',
      runAttempt: 1,
      buildId: 'bld_1',
      correlationId: 'corr-1',
    });
    expect(body).not.toHaveProperty('runnerId');
  });

  it('sanitizeRunnerMetadata redacts sensitive nested values', () => {
    const out = sanitizeRunnerMetadata({
      repository: 'acme/app',
      api_key: 'secret',
      runnerName: 'GitHub Actions 1',
    });
    expect(out.repository).toBe('acme/app');
    expect(out).not.toHaveProperty('api_key');
  });

  it('appendSignalEnvelope dedupes by idempotency key', async () => {
    const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'runner-sig-'));
    const file = path.join(dir, 'signals.jsonl');
    const signal = createSignalEnvelope({
      organizationId: 'org_test',
      signalType: 'runner.used',
      idempotencyKey: 'github-actions:acme/app:42:1:build:runner.used',
    });
    expect(await appendSignalEnvelope(file, signal)).toBe('appended');
    expect(await appendSignalEnvelope(file, signal)).toBe('deduplicated');
    expect(await dedupeSignalEnvelope(file, signal)).toBe(true);
    const lines = fs.readFileSync(file, 'utf8').trim().split('\n');
    expect(lines).toHaveLength(1);
  });
});
